  void _generateAllTypes() {
    setState(() {
      _currentUUID = UUIDGenerator.generate();
      _currentShortID = UUIDGenerator.generateShort();
      _currentTimestampedID = UUIDGenerator.generateTimestamped();
      _uuidHistory.insert(0, _currentUUID);
      if (_uuidHistory.length > 50) {
        _uuidHistory.removeLast();
      }
    });
  }

  void _generateBatch() {
    final count = int.tryParse(_batchCountController.text) ?? 5;
    final clamped = count.clamp(1, 100);
    setState(() {
      for (int i = 0; i < clamped; i++) {
        final uuid = UUIDGenerator.generate();
        _uuidHistory.insert(0, uuid);
      }
      if (_uuidHistory.length > 200) {
        _uuidHistory.removeRange(200, _uuidHistory.length);
      }
    });
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(content: Text('Generated $clamped UUIDs')),
    );
  }

  void _copyToClipboard(String text) {
    Clipboard.setData(ClipboardData(text: text));
    ScaffoldMessenger.of(context).showSnackBar(
      const SnackBar(
        content: Text('Copied to clipboard'),
        duration: Duration(seconds: 1),
      ),
    );
  }

  void _createOfflineRecord() {
    if (_titleController.text.trim().isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Please enter a title')),
      );
      return;
    }

    final record = OfflineRecord(
      id: UUIDGenerator.generate(),
      title: _titleController.text.trim(),
      description: _descriptionController.text.trim(),
      createdAt: DateTime.now(),
    );

    setState(() {
      _offlineRecords.insert(0, record);
    });

    _titleController.clear();
    _descriptionController.clear();

    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(content: Text('Record created with ID: ${record.id}')),
    );
  }

  void _simulateSync() {
    setState(() {
      for (var record in _offlineRecords) {
        record.isSynced = true;
      }
    });
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
          content:
              Text('Synced ${_offlineRecords.length} records (simulated)')),
    );
  }

  void _clearHistory() {
    setState(() {
      _uuidHistory.clear();
    });
  }

  void _clearRecords() {
    setState(() {
      _offlineRecords.clear();
    });
  }

